    return "page.jsp";
}
```



**@RequestParam**

形参注解
**请求参数**与**形参**间的关系  

```java
@RequestMapping("/requestParam2")
public String requestParam2
(@RequestParam(
		name = "userName",
		required = true,
		defaultValue = "itheima") String name
)
{
    	System.out.println("name="+name);
    	return "page.jsp";
}
```









